var results = $.steps.searchExa.response.results || [];
var context = '';
var urls = [];
results.forEach(function(r, i) {
  context += (i + 1) + '. ' + (r.title || 'Untitled') + '\n   URL: ' + r.url + '\n   ' + (r.text || '').slice(0, 400) + '\n\n';
  urls.push(r.url);
});
return { context: context, urls: urls, sourceCount: results.length };

let raw = $.steps.aiAnswer.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { text: raw }; }

var ai = $.steps.parseAI.output;
var sources = $.steps.compileSources.output;
var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':speech_balloon: ' + $.input.question.slice(0, 120), emoji: true } });
if (ai.tldr) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*TL;DR:* ' + ai.tldr } });
  blocks.push({ type: 'divider' });
}
if (ai.answer) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ai.answer.slice(0, 2900) } });
}
if (sources.urls.length > 0) {
  blocks.push({ type: 'divider' });
  var srcText = '*Sources*\n';
  sources.urls.slice(0, 5).forEach(function(u, i) { srcText += '[' + (i + 1) + '] <' + u + '>\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: srcText } });
}
if (ai.relatedQuestions && ai.relatedQuestions.length > 0) {
  blocks.push({ type: 'divider' });
  var rqText = '*Related Questions*\n';
  ai.relatedQuestions.forEach(function(q) { rqText += ':grey_question: ' + q + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: rqText } });
}
blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':robot_face: Powered by Exa Search + Claude AI | ' + sources.sourceCount + ' sources analyzed' }] });
var fallback = ai.tldr || (ai.answer ? ai.answer.slice(0, 500) : (ai.text || '').slice(0, 500));
return { blocks, fallback };
